import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom"; // ✅ agregado navigate
import axios from "axios";
import "../styles/recuperar.css";

function RecuperarPassword() {
  const [email, setEmail] = useState("");
  const [mensaje, setMensaje] = useState("");
  const [submitted, setSubmitted] = useState(false);

  // 🔥 LOGIN (AGREGADO)
  const [documento, setDocumento] = useState("");
  const [password, setPassword] = useState("");
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();

    try {
      const response = await axios.post("http://127.0.0.1:8000/login", {
        numero_documento: documento,
        password: password,
      });

      localStorage.setItem("token", response.data.token);

      alert("Login exitoso");

      navigate("/cuenta");

    } catch (error) {
      console.log(error.response);
      alert(error.response?.data?.detail || "Error en login");
    }
  };

  // 🔥 TU CÓDIGO ORIGINAL (NO MODIFICADO)
  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!email.trim()) {
      setMensaje("❌ Por favor ingresa tu correo electrónico.");
      setSubmitted(false);
      return;
    }

    try {
      const response = await axios.post("http://127.0.0.1:8000/recuperar", {
        correo: email,
      });

      console.log(response.data);

      setMensaje("");
      setSubmitted(true);

    } catch (error) {
      console.log(error.response);
      setMensaje(error.response?.data?.detail || "Error al enviar correo");
      setSubmitted(false);
    }
  };

  return (
    <div className="recuperar-container">
      <h2 className="titulo">Recuperar Contraseña</h2>
      <p className="subtitulo">
        Ingresa tu correo electrónico para restablecer tu contraseña.
      </p>

      <form className="formulario" onSubmit={handleSubmit}>
        <label htmlFor="email">Correo electrónico</label>

        <div className="input-box">
          <span className="icon">📧</span>
          <input
            type="email"
            id="email"
            placeholder="tu-correo@ejemplo.com"
            value={email}
            onChange={(e) => {
              setEmail(e.target.value);
              setMensaje("");
            }}
            required
          />
        </div>

        {mensaje && <p className="mensaje-error">{mensaje}</p>}

        {submitted && (
          <p className="mensaje-exito">
            ✔️ Correo de recuperación enviado
          </p>
        )}

        <button type="submit" className="btn">
          {submitted ? "Enviado" : "Enviar correo"}
        </button>

        <p className="texto-sec">
          ¿Ya recuperaste tu contraseña?{" "}
          <Link to="/login">Inicia sesión aquí</Link>
        </p>
      </form>
    </div>
  );
}

export default RecuperarPassword;
